function u(){function e(t){if(!t)return"—";const r=new Date(t);return isNaN(r.getTime())?t:r.toLocaleDateString("fr-FR",{day:"2-digit",month:"2-digit",year:"numeric"})}function n(t){if(!t)return"—";if(/^\d{2}:\d{2}$/.test(t))return t;const r=new Date(t);return isNaN(r.getTime())?t:r.toLocaleTimeString("fr-FR",{hour:"2-digit",minute:"2-digit"})}function i(t){return t==null?"—":new Intl.NumberFormat("fr-FR",{style:"currency",currency:"EUR"}).format(t)}return{formatDate:e,formatTime:n,formatCurrency:i}}export{u};
